#include <bits/stdc++.h>
using namespace std;

const int N=4e4+10;

int n,m,k,ans;
bool h[N],l[N],d[N],f[N];

bool check(int x,int y){
    if(x<1 || x>n || y<1 || y>m) return false;
    return !(h[x] || l[y] || d[x-y+n] || f[x+y]);
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    ans=n*m;
    while(k--){
        int x,y;
        scanf("%d%d",&x,&y);
        for(int i=1;i<=m;i++)
            ans-=check(x,i);
        h[x]=true;
        for(int i=1;i<=n;i++)
            ans-=check(i,y);
        l[y]=true;
        for(int i=1;i<=n;i++)
            ans-=check(i,i-x+y);
        d[x-y+n]=true;
        for(int i=1;i<=n;i++)
            ans-=check(i,x+y-i);
        f[x+y]=true;
    }
    printf("%d",ans);
    return 0;
}
